import http from "../01_axios"
import {
  apiDeletePackage,
  apiGetListPackage,
  apiInsertPacakge,
  apiUpdatePackage
} from "./urls"



const getListPackage = body => http.post(apiGetListPackage, body)
const insertPacakge = body => http.post(apiInsertPacakge, body)
const updatePackage = body => http.post(apiUpdatePackage, body)
const deletePackage = body => http.post(apiDeletePackage, body)

const MembershipTypeService = {
  getListPackage,
  insertPacakge,
  updatePackage,
  deletePackage
}
export default MembershipTypeService
